const b = $input.first().json.body ?? $input.first().json;
const task = b.task ?? 'generate';
const evLine = e => `- ${e.date ?? ''} [${e.category}] ${e.title}${e.detail ? ` — ${String(e.detail).slice(0,240)}` : ''}`;
const logLine = l => `${l.date}: built ${l.built ?? '-'}; learned ${l.learned ?? '-'}${l.blocked ? `; blocked by ${l.blocked}` : ''}${l.energy ? `; energy ${l.energy}/5` : ''}`;
let system = `You are Super Dent X AI, a build-in-public writer for founders. Sound like a real founder, never like AI. No 'exciting news' openers. Be specific — quote their real event details, amounts and numbers. Revenue/customer/milestone events are the headline: if an amount or payout appears in the details, celebrate it with the exact figure. Tweets max 280 chars or thread format. LinkedIn 800-1200 chars.`;
let user = '';
if (task === 'chat') {
  system = `You are the Super Dent X Co-pilot for a founder building ${b.projectName}. You have their full shipping log including event details, blockers and energy levels. Be a real companion: specific, warm, brief (2-4 sentences), reference actual events by name, date and detail — especially money: first payouts and big payments deserve real celebration with the exact amount. Motivate with receipts, never generic hype. If asked for a briefing, open proactively with today + this week + the single best next move.`;
  user = `Streak: ${b.streak} days.
Recent events:
${(b.events??[]).map(evLine).join('
')}

Reflections:
${(b.dailyLogs??[]).map(logLine).join('
')}

Question: ${b.question}`;
} else if (task === 'humanize') {
  user = `Project: ${b.projectName}
Platform: ${b.platform}
Voice: ${b.tone}

Raw notes from the builder:
${b.raw}

Shape this into a post. Keep their facts and voice. It must read like a human typed it.`;
} else if (task === 'fuse') {
  user = `Project: ${b.projectName}
Platform: ${b.platform}
Voice: ${b.tone}

Ships picked from the log:
${(b.picked??[]).map(evLine).join('
')}

Their current state, raw:
${b.state}

Fuse the logged facts with the human feeling into one post.`;
} else {
  user = `Project: ${b.projectName} — ${b.projectTagline}
Platform: ${b.platform}
Voice: ${b.tone}

Events (with details where logged):
${(b.events??[]).map(evLine).join('
')}

Reflections:
${(b.dailyLogs??[]).map(logLine).join('
')}

Write the ${b.platform} post in ${b.tone} voice.`;
}
return [{ json: { system, user } }];
